;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){((Drupal2,OVH2)=>{const odsSkipLink={constants:{skipText:OVH2.t("Skip to main content"),class:["focusable","visually-hidden"]},elements:{link:document.createElement("a")},methods:{initialize:()=>{window.addEventListener("DOMContentLoaded",()=>{odsSkipLink.elements.link.href="#main-content";odsSkipLink.elements.link.classList.add(...odsSkipLink.constants.class);const text=document.createTextNode(odsSkipLink.constants.skipText);odsSkipLink.elements.link.appendChild(text);odsSkipLink.elements.link.setAttribute("data-skip-link","");document.querySelector("body")?.prepend(odsSkipLink.elements.link);});}},attach(){odsSkipLink.methods.initialize();}};Drupal2.behaviors.odsSkipLink=odsSkipLink;})(Drupal,OVH);}};});})();
